    function TotalTrees() {
        Ext.getCmp('TotalTrees').setValue(parseInt((parseFloat(Ext.getCmp('PohonTotal').getValue()) || 0) / (parseFloat(Ext.getCmp('GardenHaUnCertified').getValue()) || 1)))
        Ext.getCmp('totalproduktivitas').setValue(parseInt((parseFloat(Ext.getCmp('totalpanen').getValue()) || 0) / (parseFloat(Ext.getCmp('GardenHaUnCertified').getValue()) || 1)));
        if (parseFloat(Ext.getCmp('TotalTrees').getValue()) < 100 || parseFloat(Ext.getCmp('TotalTrees').getValue()) > 1500) Ext.getCmp('TotalTrees').addCls('notif-red');
        else Ext.getCmp('TotalTrees').removeCls('notif-red');
        if (parseFloat(Ext.getCmp('totalproduktivitas').getValue()) < 0 || parseFloat(Ext.getCmp('totalproduktivitas').getValue()) > 3000) Ext.getCmp('totalproduktivitas').addCls('notif-red');
        else Ext.getCmp('totalproduktivitas').removeCls('notif-red');
    }

