    function totalpanen() {
        Ext.getCmp('totalpanen').setValue((parseFloat(Ext.getCmp('PanenTrekKgThn').getValue()) || 0) + (parseFloat(Ext.getCmp('PanenBiasaKgThn').getValue()) || 0) + (parseFloat(Ext.getCmp('PanenRayaKgThn').getValue()) || 0));
        Ext.getCmp('totalproduktivitas').setValue(parseInt((parseFloat(Ext.getCmp('totalpanen').getValue()) || 0) / (parseFloat(Ext.getCmp('GardenHaUnCertified').getValue()) || 1)));
        if (parseFloat(Ext.getCmp('totalpanen').getValue()) < 0 || parseFloat(Ext.getCmp('totalpanen').getValue()) > 3000) Ext.getCmp('totalpanen').addCls('notif-red');
        else Ext.getCmp('totalpanen').removeCls('notif-red');
    }

