    function endis() {
        if (Ext.getCmp('FrUrea').getValue() > 0 || Ext.getCmp('DpUrea').getValue() > 0 || Ext.getCmp('FrZa').getValue() > 0 || Ext.getCmp('DoZa').getValue() > 0 || Ext.getCmp('FrTsp').getValue() > 0 || Ext.getCmp('DoTsp').getValue() > 0 || Ext.getCmp('FrNpk').getValue() > 0 || Ext.getCmp('DoNpk').getValue() > 0 || Ext.getCmp('FrKcl').getValue() > 0 || Ext.getCmp('DoKcl').getValue() > 0 || Ext.getCmp('FrLain').getValue() > 0 || Ext.getCmp('FrFoliar').getValue() > 0 || Ext.getCmp('DoFoliar').getValue() > 0 || Ext.getCmp('DoLain').getValue() > 0) {
            Ext.getCmp('manayang').setDisabled(false);
        } else {
            Ext.getCmp('manayang').setDisabled(true);
        }
    }

