    function submitOnEnter(field, event) {
        if (event.getKey() == event.ENTER) {
            store.load({
                params: {
                    sert: Ext.getCmp('sertifikasis').getValue(),
                    key: Ext.getCmp('key').getValue(),
                    kab: {
                        array: Ext.encode(Ext.getCmp('Kab').getValue())
                    },
                    ord: Ext.getCmp('Order').getValue()
                }
            });
        }
    }

