                                        AnggotaName: e.record.data.AnggotaName,
                                        HubunganKeluarga: e.record.data.hubungan,
                                        AnggotaAge: e.record.data.AnggotaAge,
                                        AnggotaGender: e.record.data.kelamin,
                                        StatusSekolah: e.record.data.sekolah
