    //update garden =====================================================================================================
    function displayFormGarden() {
        if (!winGarden.isVisible()) {
            DataFormGarden.getForm().reset();
            winGarden.show();
        } else {
            winGarden.hide(this, function() {});
            winGarden.toFront();
        }
    }

    function checking() {
        if (Ext.getCmp('PruningPlants').getValue()) {
            Ext.getCmp('FrequentPruning').setDisabled(false);
            Ext.getCmp('HighPruning').setDisabled(false);
        } else {
            Ext.getCmp('FrequentPruning').setDisabled(true);
            Ext.getCmp('HighPruning').setDisabled(true);
        }
    }

    function setKlon() {
        Ext.getCmp('TotalKlon').setValue((parseInt(Ext.getCmp('TSH858Nr').getValue()) || 0) + (parseInt(Ext.getCmp('RCC70Nr').getValue()) || 0) + (parseInt(Ext.getCmp('RCC71Nr').getValue()) || 0) + (parseInt(Ext.getCmp('RCC72Nr').getValue()) || 0) + (parseInt(Ext.getCmp('RCC73Nr').getValue()) || 0) + (parseInt(Ext.getCmp('LokalNr').getValue()) || 0) + (parseInt(Ext.getCmp('S1Nr').getValue()) || 0) + (parseInt(Ext.getCmp('S2Nr').getValue()) || 0) + (parseInt(Ext.getCmp('S3Nr').getValue()) || 0) + (parseInt(Ext.getCmp('ICRRI3Nr').getValue()) || 0) + (parseInt(Ext.getCmp('ICRRI4Nr').getValue()) || 0) + (parseInt(Ext.getCmp('ICRRI5Nr').getValue()) || 0) + (parseInt(Ext.getCmp('M01Nr').getValue()) || 0) + (parseInt(Ext.getCmp('M06Nr').getValue()) || 0) + (parseInt(Ext.getCmp('THRNr').getValue()) || 0) + (parseInt(Ext.getCmp('RCLNr').getValue()) || 0) + (parseInt(Ext.getCmp('J45Nr').getValue()) || 0) + (parseInt(Ext.getCmp('CloneLainNr').getValue()) || 0))
    }
    
