var wFormCertificationAudit = Ext.create('widget.window', {
//     id: 'FormCertificationAudit',
    title: lang('Certification Log'),
    header: {
        titlePosition: 2,
        titleAlign: 'center'
    },
    closable: false,
    closeAction: 'hide',
    items: [FormCertificationAudit],    
    buttons: [{
        text: lang('Batal'),
        handler: function() {
//            var win = Ext.getCmp('FormCertificationAudit');
            Ext.getCmp('FormCertificationAudit').getForm().reset();
//            win.hide();
            wFormCertificationAudit.hide();
        }
    }, {
        id: 'BtnSiswaGridSimpan',
        text: lang('Simpan'),
        handler: function() {
            var form = Ext.getCmp('FormCertificationAudit').getForm();
            if (form.isValid()) {
                form.submit({
                    success: function(form, action) {
                        Ext.Msg.alert('Success', action.result.message);
                        Ext.getCmp('FormCertificationAudit').getForm().reset();
                        wFormCertificationAudit.hide();

                        //set data terakhir audit log
                        Ext.Ajax.request({
                            waitMsg: 'Please Wait',
                            url: m_last_audit,
                            method: 'GET',
                            params: {
                                farmer_id: Ext.getCmp('gFarmerID').getValue(),
                                GardenNr: Ext.getCmp('GardenNr').getValue(),
                                gSurveyNr: Ext.getCmp('gSurveyNr').getValue(),
                                certification:Ext.getCmp('Certification').getValue().Certification
                            },
                            success: function(response, opts) {
                                var obj = Ext.decode(response.responseText);
                                if(obj.success)
                                {
                                    console.log(obj.data.StatusAudit);
                                    Ext.getCmp('StatusAudit'+obj.data.StatusAudit).setValue(obj.data.StatusAudit);
                                    Ext.getCmp('ICSDate').setValue(obj.data.ICSDate);
                                    Ext.getCmp('DateRevisionAudit').setValue(obj.data.DateRevisionAudit);
                                    Ext.getCmp('CommentAudit').setValue(obj.data.CommentAudit);
                                    Ext.getCmp('RecommendationAudit').setValue(obj.data.RecommendationAudit);
                                }
                            },
                            failure: function(response, opts) {
                                var obj = Ext.decode(response.responseText);
                                Ext.MessageBox.alert('error', 'Could not connect to the database. Retry later');
                            }
                        });
                        
                        storeGridAuditActivity.load({
                            params: {
                               farmer_id: Ext.getCmp('gFarmerID').getValue(),
                                GardenNr: Ext.getCmp('GardenNr').getValue(),
                                gSurveyNr: Ext.getCmp('gSurveyNr').getValue(),
                                certification:Ext.getCmp('Certification').getValue().Certification
                            }
                        });
//                        storeGridAuditActivity.load();
                        
                        wFormCertificationAudit.hide();
                    },
                    failure: function(form, action) {
                        Ext.Msg.alert('Failed', action.result ? action.result.message : 'No response');
                        //                            storeGridAuditActivity.load();
                    }
                });
                
                 
            } else {
                Ext.Msg.alert("Error!", "Your form is invalid!");
            }
        }
    }]
});

