                                                    Ext.getCmp('FarmerIDFormCert').setValue(Ext.getCmp('gFarmerID').getValue());
                                                    Ext.getCmp('GardenNrFormCert').setValue(Ext.getCmp('GardenNr').getValue());
                                                    Ext.getCmp('SurveyNrFormCert').setValue(Ext.getCmp('gSurveyNr').getValue());
